/*
  PopStateManager helper for browser history popstate handling.
*/

import History from './History.js';
import State from './State.js';

const MOD = '[app.PopStateManager]';

function normalizeWorkspace(value) {
    return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function resolveHost(controller, host) {
    if (host && typeof host === 'object') {
        return host;
    }

    if (controller && controller.root && controller.root.host) {
        return controller.root.host;
    }

    if (controller && controller.host) {
        return controller.host;
    }

    return null;
}

function resolveHandlerKey(spaState) {
    if (!spaState || typeof spaState !== 'object') {
        return null;
    }

    return spaState.popstate ?? spaState.popState ?? spaState.route ?? null;
}

class PopStateManager {

    constructor({lib, conf = {}, identifier, controller, asserted, env = null, host = null} = {}){
        this.lib = lib;
        this.controller = controller || null;
        this.asserted = asserted || (this.controller && this.controller.asserted) || null;
        this.env = normalizeWorkspace(env);

        if (!this.lib || !this.lib.hash || typeof this.lib.hash.to !== 'function' || typeof this.lib.hash.merge !== 'function') {
            throw new Error(`${MOD} requires lib.hash.to and lib.hash.merge.`);
        }

        const confObj = this.lib.hash.to(conf);
        this.conf = this.lib.hash.merge(
            confObj,
            {
                stateKey: confObj.stateKey || 'spa', // this is our sandbox
                last: null,
            }
        );
        this.conf.debug = confObj.debug === true || this.conf.debug === true;

        this.identifier = identifier || new Date().toString();
        const initialHost = resolveHost(this.controller, host);
        this.history = new History({
            lib: this.lib,
            host: initialHost,
        });
        this.state = new State({
            lib: this.lib,
            history: this.history,
            conf: this.conf,
            identifier: this.identifier,
        });
        this.popStateHandlers = Object.create(null);
        this.popStateListener = null;
        this.popStateHost = null;
    }

    setHost(host){
        if (this.history && typeof this.history.setHost === 'function') {
            this.history.setHost(host);
        } else if (this.history) {
            this.history.host = host;
        }
        return this.history;
    }

    debug(...args){
        if (this.conf && this.conf.debug) {
            console.error(...args);
        }
    }

    syncHistoryState(spaState = null){
        if (!spaState || typeof spaState !== 'object') {
            return this.history.snapshot();
        }

        const restore = {
            statePos: spaState.pos,
        };

        if (Array.isArray(spaState.history)) {
            restore.urlHistory = spaState.history;
        }

        // Translate the SPA envelope into the generic history helper state.
        return this.history.restore(restore);
    }

    setEnv(env = null){
        this.env = normalizeWorkspace(env);
        return this.env;
    }

    buildPopstateContext({event, currentURL, spaState, isSPA} = {}){
        const spa = this.controller || null;
        const globalEnv = spa && spa.env ? spa.env : {};
        return {
            lib: this.lib,
            spa,
            root: this.controller && this.controller.root ? this.controller.root : null,
            routeState: this,
            popStateManager: this,
            env: {
                global: globalEnv,
                event: this.env,
            },
            event,
            currentURL,
            previousURL: spaState && typeof spaState === 'object' ? (spaState.previous ?? spaState.back ?? null) : null,
            state: spaState,
            isSPA,
        };
    }

    loadUrl(url = undefined){
        const host = this.history && this.history.host ? this.history.host : null;
        const locationObj = host && host.location ? host.location : null;

        if (!host || !locationObj || typeof locationObj.href !== 'string') {
            throw new Error(`${MOD} requires a host with location.href.`);
        }

        if (url === undefined || url === null) {
            url = locationObj.href;
        }

        if (typeof locationObj.reload === 'function' && url === locationObj.href) {
            locationObj.reload();
            return url;
        }

        locationObj.href = url;
        return url;
    }

    unregister(target = undefined){
        if(!target){
            this.debug('removing all popstate handlers');
            let keys = Object.keys(this.popStateHandlers);
            for (let key of keys){
                delete(this.popStateHandlers[key] );
            }
            return this.popStateHandlers;
        }

        delete(this.popStateHandlers[target]);
        return this.popStateHandlers;
    }

    register(key, handler){
        const resolvedHandler = this.lib && this.lib.func && typeof this.lib.func.get === 'function'
            ? this.lib.func.get(handler)
            : handler;

        if (typeof resolvedHandler !== 'function') {
            throw new Error(`${MOD} requires handler function.`);
        }

        this.popStateHandlers[key] = resolvedHandler;
        return resolvedHandler;
    }

    start(){
        const host = this.popStateHost || this.history.host;

        if (!host || !host.location || !host.history) {
            throw new Error(`${MOD} requires a host with location and history.`);
        }

        if (this.popStateListener && this.popStateHost && typeof this.popStateHost.removeEventListener === 'function') {
            this.popStateHost.removeEventListener('popstate', this.popStateListener);
        }

        const popStateHandler = (e) => {
            const currentURL = host.location.href;
            const pageState = e && e.state && typeof e.state === 'object'
                ? e.state[this.conf.stateKey]
                : null;

            if (!pageState) {
                return;
            }

            const spaState = pageState;
            const isSPA = spaState.type;
            const previousURL = spaState.previous ?? spaState.back ?? null;
            const handlerKey = resolveHandlerKey(spaState);

            if (!isSPA) {
                return;
            }

            if (spaState.id !== this.identifier) {
                this.debug('expired state.');
                if (typeof host.removeEventListener === 'function') {
                    host.removeEventListener('popstate', popStateHandler);
                }
                this.loadUrl();
                return;
            }

            const stateStack = this.history.stateStack;
            const pageStateAtPos = stateStack[spaState.pos];
            const currentSpaState = pageStateAtPos ? pageStateAtPos[this.conf.stateKey] : null;

            if (spaState.pos >= stateStack.length || !currentSpaState || spaState.url !== currentSpaState.url) {
                this.debug('STATE MISMATCH', spaState, pageStateAtPos);
                return;
            }

            if (currentURL !== spaState.url) {
                this.debug('currentUrl / state url mismatch!', currentURL, spaState.url);
                return;
            }

            // keep the internal cursor aligned with the browser's history entry
            this.syncHistoryState(spaState);

            const handlerContext = this.buildPopstateContext({
                event: e,
                currentURL,
                spaState,
                isSPA,
                previousURL,
            });

            if (isSPA === 'start') {
                const startHandler = this.popStateHandlers[handlerKey] || this.popStateHandlers.start || this.popStateHandlers.default;
                if (startHandler) {
                    return startHandler(e, currentURL, handlerContext);
                }
                this.loadUrl(currentURL);
                return;
            }

            const handler = this.popStateHandlers[handlerKey] || this.popStateHandlers.default;
            if (!handler) {
                throw new Error(`pop state handler ${String(handlerKey)} not found`);
            }

            return handler(e, currentURL, handlerContext);
        };

        this.popStateListener = popStateHandler;
        this.popStateHost = host;
        host.addEventListener('popstate', popStateHandler);
        return popStateHandler;
    }

    stop(){
        const host = this.popStateHost || this.history.host;

        if (this.popStateListener && host && typeof host.removeEventListener === 'function') {
            host.removeEventListener('popstate', this.popStateListener);
        }

        this.popStateListener = null;
        this.popStateHost = null;
        return this;
    }

    set(state){
        const nextState = this.state.set(state);
        this.conf.last = this.history && this.history.host && this.history.host.location
            ? this.history.host.location.href
            : this.conf.last;
        return nextState;
    }


    push(url, title = '', state){
        const nextState = this.state.push(url, title, state);
        this.conf.last = url;
        return nextState;
    }

}

export default PopStateManager;
export { PopStateManager };
