/**
 * ManagedInterval
 * ----------------
 * Represents a single named, managed interval registered under an IntervalManager.
 *
 * Responsibilities:
 * - Own per-interval configuration (timing, overlap policy, error policy, environment overrides)
 * - Own lifecycle state (running / paused / cancelled)
 * - Execute user callback with a standardized context (sync or async)
 * - Enforce overlap semantics: skip / coalesce / queue
 * - Enforce error handling semantics (continue / pause / cancel / backoff)
 * - Support one-time lifecycle hooks: onConstruct / onDestroy
 *
 * Notes:
 * - Scheduling uses the manager's clock abstraction if provided.
 * - Environment gating is enforced consistently in start/runNow/step/_scheduleNext/_tick.
 */

/**
 * Default maximum number of queued runs when overlapPolicy === 'queue' and maxQueue is unset.
 * @type {number}
 */
const DEFAULT_MAX_QUEUE = 100;

/**
 * Queue error behavior policies (applied only when overlapPolicy === 'queue').
 * @readonly
 * @enum {string}
 */
export const QUEUE_ERROR_POLICIES = Object.freeze({
    CLEAR: 'clear',        // drop entire queue on error (default, safest)
    PRESERVE: 'preserve',  // keep queue intact
    CAP: 'cap',            // cap queue to 1 on error
    DROP_ONE: 'dropOne',   // decrement queue by one on error
});


/**
 * Create a new ManagedInterval.
 *
 * @param {IntervalManager} manager
 *        Parent IntervalManager instance.
 *
 * @param {Object} config
 *
 * @param {string} [config.name]
 *        Interval name (used for lookup, signaling, control).
 *        If omitted, a generated name is used.
 *
 * @param {number} [config.everyMs=1000]
 *        Base interval period in milliseconds. Values < 1 are clamped to 1.
 *
 * @param {number} [config.maxRuns=0]
 *        Maximum number of executions. 0 means unlimited.
 *
 * @param {'low'|'normal'|'high'} [config.priority='normal']
 *        Execution priority hint.
 *
 * @param {'skip'|'coalesce'|'queue'} [config.overlapPolicy='coalesce']
 *        Behavior when a tick occurs while execution is already inflight.
 *        - 'skip'     : drop overlapping ticks
 *        - 'coalesce' : remember exactly one pending run
 *        - 'queue'    : queue multiple runs (bounded by maxQueue unless unbounded)
 *
 * @param {number|null|undefined} [config.maxQueue]
 *        Queue cap for overlapPolicy === 'queue'.
 *        - null/undefined => DEFAULT_MAX_QUEUE
 *        - 0 or Infinity  => unbounded
 *        - negative/NaN   => DEFAULT_MAX_QUEUE
 *
 * @param {'clear'|'preserve'|'cap'|'dropOne'} [config.queueErrorPolicy='clear']
 *        Behavior for queued backlog when a tick errors (overlapPolicy === 'queue' only).
 *
 * @param {'continue'|'pause'|'cancel'|'backoff'} [config.errorPolicy='continue']
 *        Behavior when fn(ctx) throws or rejects.
 *
 * @param {Function} config.fn
 *        Execution callback invoked with a standardized context object.
 *        May be synchronous or async (returning a Promise).
 *
 * @param {(ctx: import('./types').IntervalContext) => void | Promise<void>} [config.onConstruct]
 *        Optional one-time initialization hook.
 *        Runs once per lifecycle (or again after reset()) before the first user tick.
 *        Does not count toward runs/maxRuns.
 *
 * @param {'pause'|'retry'|'cancel'} [config.constructErrorPolicy='pause']
 *        Policy for failures in onConstruct.
 *        - 'pause'  : pause the interval
 *        - 'retry'  : retry onConstruct on the next eligible tick
 *        - 'cancel' : cancel the interval
 *
 * @param {(ctx: import('./types').IntervalContext, reason: string) => void | Promise<void>} [config.onDestroy]
 *        Optional one-time teardown hook invoked during cancel(reason).
 *        Does not count toward runs/maxRuns.
 *
 * @param {Object} [config.workspace]
 *        Mutable user-defined workspace injected into ctx.workspace.
 *
 * @param {boolean} [config.runWhenHidden=false]
 *        If true, the interval is allowed to run while manager environment is non-visible.
 *
 * @param {boolean} [config.runWhenOffline=false]
 *        If true, the interval is allowed to run while manager environment is offline.
 *
 * @param {boolean} [config.warnOnDestroyError]
 *        If provided, overrides manager-level warnOnDestroyError for this interval.
 * @example
 * // Sample JSON-style interval definition
 * {
 *   "name": "users:refresh",
 *   "everyMs": 5000,
 *   "maxRuns": 0,
 *   "priority": "low",
 *   "runWhenHidden" : false,
 *   "runWhenOffline" : false,
 *   "overlapPolicy": "coalesce",
 *   "errorPolicy": "backoff",
 *   "workspace": {
 *     "lastCursor": null,
 *     "failures": 0
 *   },
 *   "fn": "(ctx) => { interval, logic  }"
 *   onConstruct: (ctx) => {
 *     // one-time setup (sync or async)
 *     ctx.workspace.session = startSession();
 *   },
 *   onDestroy: (ctx, reason) => {
 *     // one-time teardown (sync or async)
 *     console.log(`Destroyed: ${reason}`);
 *     ctx.workspace.session?.close();
 *   }
 * }
 */
class ManagedInterval {
    constructor(manager, config = {}) {
        /**
         * Back-reference to IntervalManager
         */
        this.manager = manager;

        /**
         * Interval identity
         */
	this.name = String(config.name || `unnamed - interval-${Date.now()}`);
        /**
         * Base interval period (ms)
         */
	//waffling. fafo and decide later.
	//this.everyMs = Math.max(10, Number(config.everyMs || 0));
	this.everyMs = Math.max(1, Number(config.everyMs) || 1000);
        /**
         * Maximum number of runs (0 = unlimited)
         */
        this.maxRuns = Number(config.maxRuns || 0);

        /**
         * Execution priority
         * low | normal | high
         */
        this.priority = config.priority || 'normal';

        /**
         * Overlap handling policy
         * skip | coalesce | queue
         */
        this.overlapPolicy = config.overlapPolicy || 'coalesce';

        /**
         * Error handling policy
         * continue | pause | cancel | backoff
         */
        this.errorPolicy = config.errorPolicy || 'continue';
	/**
	 * Visibility policy
	 * - If true, interval continues running when document/tab is hidden.
	 * - If false, interval will not tick while hidden (default).
	 */

	this.runWhenHidden = (typeof config.runWhenHidden === 'boolean')
	    ? config.runWhenHidden
	    : false;
	
	this.runWhenOffline = (typeof config.runWhenOffline === 'boolean')
	    ? config.runWhenOffline
	    : false;

	const managerWarnOnDestroyError =
	      (typeof this.manager?.opts?.warnOnDestroyError === 'boolean')
	      ? this.manager.opts.warnOnDestroyError
	      : true;

	this.warnOnDestroyError = (typeof config.warnOnDestroyError === 'boolean')
	    ? config.warnOnDestroyError
	    : managerWarnOnDestroyError;
	
        /**
         * Injected mutable workspace
         */
        this.workspace = config.workspace ?? {};

        /**
         * Execution callback
	 * may change to allow symbolic funcions / fns / chain of either at later date.
         */
	
	if (typeof config.fn !== 'function') {
	    throw new Error(
		`ManagedInterval "${this.name || '<unnamed>'}": config.fn must be a function`
	    );
	}
	this.fn = config.fn;

	/**
	 * Optional lifecycle callbacks.
	 * Neither callback counts toward runs or maxRuns.
	 */

	/**
	 * One-time initialization hook.
	 *
	 * Invoked exactly once per lifecycle:
	 * - Before the first user execution (`fn(ctx)`)
	 * - Or again after a call to `reset()`
	 *
	 * Execution timing:
	 * - Runs on the first *eligible* tick (i.e. when not gated by environment or lifecycle state)
	 * - May be synchronous or async (Promise-returning)
	 *
	 * Errors are handled according to `constructErrorPolicy`.
	 *
	 * @type {((ctx: import('./types').IntervalContext) => void | Promise<void>) | null}
	 */
	this.onConstruct = typeof config.onConstruct === 'function' ? config.onConstruct : null;
	
	const cep = config.constructErrorPolicy;
	this.constructErrorPolicy = (cep === 'pause' || cep === 'retry' || cep === 'cancel') ? cep : 'pause';
	
	/**
	 * One-time teardown hook.
	 *
	 * Invoked exactly once when the interval is cancelled:
	 * - Before timers are cleared
	 * - Before the interval may be removed from the manager
	 *
	 * Execution semantics:
	 * - Receives a fresh execution context and the cancellation reason
	 * - May be synchronous or async (Promise-returning)
	 * - Errors are caught and reported but never prevent cancellation
	 *
	 * This callback:
	 * - Does NOT count toward runs or maxRuns
	 * - Must NOT schedule or trigger new ticks
	 *
	 * @type {((ctx: import('./types').IntervalContext, reason: string) => void | Promise<void>) | null}
	 */
	this.onDestroy   = typeof config.onDestroy   === 'function' ? config.onDestroy   : null;
	
        /**
         * Runtime state
         */
        this.status = 'paused';        // running | paused | cancelled
        this.runs = 0;
        this.startedAt = null;
        this.lastRunAt = null;
        this.nextRunAt = null;

        /**
         * Execution context / metadata
         */
        this.lastReason = null;        // timer | manual | signal | resume
        this.lastError = null;

        /**
         * Concurrency / overlap state
         */
        this.inflight = false;
        this.pending = false;

        /**
         * Backoff / reschedule state
         */
        this.backoffMs = null;

        /**
         * Last received signal
         */
        this.lastSignal = null;

        /**
         * Internal timer reference
         */
        this._timer = null;

	/**
	 * Tracks whether we've seen an error since the last successful run.
	 * Used to reset backoff after recovery (1 successful run).
	 */
	this._hadErrorSinceSuccess = false;

	/**
	 * Flag to track whether onConstruct has already run in the current lifecycle.
	 * Reset on .reset() so onConstruct can re-run after reset > start.
	 * 
	 * @private
	 * @type {boolean}
	 */
	this._hasConstructRun = false;

	/**
	 * used for stepping through intervals.
	 */
	
	this._stepOnce = false; //initializing the variable in case its needed

	/**
	 * Deferred reset marker used when reset() is requested during inflight execution.
	 * Applied in finalize paths after the active tick settles.
	 *
	 * @private
	 * @type {boolean}
	 */
	this._resetPending = false;

	// Queue / overlap state
	this.queueCount = 0;
	this.maxQueue = this._maxQueueSauce(config.maxQueue);

	// Queue error behavior
	this.queueErrorPolicy = Object.values(QUEUE_ERROR_POLICIES).includes(config.queueErrorPolicy)
	    ? config.queueErrorPolicy
	    : QUEUE_ERROR_POLICIES.CLEAR;
    }


    /**
     * Normalize a maxQueue input to a numeric cap.
     *
     * Semantics:
     * - null/undefined => DEFAULT_MAX_QUEUE
     * - 0 or Infinity  => unbounded
     * - negative/NaN   => DEFAULT_MAX_QUEUE
     * - positive finite => cap
     *
     * @private
     * @param {*} mq
     * @returns {number} Normalized maxQueue
     */
    _maxQueueSauce(mq) {
	if (mq == null) return DEFAULT_MAX_QUEUE; // null/undefined => default cap

	const n = Number(mq);

	// Infinity => unbounded
	if (n === Infinity) return Infinity;

	// NaN, -Infinity, negative => default cap
	if (!Number.isFinite(n) || n < 0) return DEFAULT_MAX_QUEUE;

	// 0 => unbounded, positive finite => cap
	return n;
    }
    
    /* ===========================
     * Lifecycle Control
     * =========================== */

    /**
     * Start or resume this interval.
     *
     * Semantics:
     * - Idempotent: calling while running is a no-op.
     * - Will not start if cancelled or manager disposed.
     * - Will not schedule if environment gating blocks execution (hidden/offline/suspended),
     *   unless this interval overrides with runWhenHidden/runWhenOffline.
     *
     * @param {string} [reason='start']
     * @returns {void}
     */
    start(reason = 'start') {
	if (this.status === 'cancelled') return;
	if (this.manager?.disposed === true) return;

	// Hard gate: manager suspension
	if (this.manager?.environment?.suspended === true) {
            this.status = 'paused';
            this.lastReason = 'suspended';
            this._clearTimer();
            this.nextRunAt = null;
            return;
	}

	// Environment gate: hidden/offline policies
	if (typeof this._shouldPauseDueToEnvironment === 'function' && this._shouldPauseDueToEnvironment()) {
            const env = this.manager?.environment ?? {};
            const opts = this.manager?.opts ?? {};

            let why = 'environment';
            const pauseWhenHidden = opts.pauseWhenHidden !== false;
            const pauseWhenOffline = opts.pauseWhenOffline !== false;

            if (pauseWhenHidden && env.visible === false && !this.runWhenHidden) why = 'hidden';
            else if (pauseWhenOffline && env.online === false && !this.runWhenOffline) why = 'offline';

            this.status = 'paused';
            this.lastReason = why;

            this._clearTimer();
            this.nextRunAt = null;
            return;
	}

	// Idempotent
	if (this.status === 'running') return;

	this.status = 'running';
	this.lastReason = reason || 'start';

	const now = this.manager?.clock?.now ? this.manager.clock.now() : Date.now();
	if (!this.startedAt) this.startedAt = now;

	this._clearTimer();

	const delay =
              (typeof this.backoffMs === 'number' && this.backoffMs >= 0)
              ? this.backoffMs
              : this.everyMs;

	this.backoffMs = null;
	this._scheduleNext(delay);
    }
    /**
     * Execute exactly one tick, then ensure the interval is paused after completion.
     *
     * Semantics:
     * - If inflight: does not start a second execution; instead guarantees pause
     *   once inflight completes.
     * - If overlapPolicy === 'queue' and queueCount > 0: consumes one queued unit before stepping.
     * - If pending (coalesce): consumes the pending unit before stepping.
     * - If a step executes, it results in paused state after completion (success or error).
     * - If environment gating blocks execution at call time, no step runs and lifecycle state is unchanged.
     *
     * @param {string} [reason='step']
     * @returns {void}
     */
    step(reason = 'step') {
	if (this.status === 'cancelled') return;
	if (this.manager?.disposed === true) return;

	// Obey environment gating (do not force execution if policy blocks it)
	if (
            typeof this._shouldPauseDueToEnvironment === 'function' &&
		this._shouldPauseDueToEnvironment()
	) {
            return;
	}

	// If an execution is already inflight, we can't "step" another run now.
	// But we *can* guarantee the interval pauses as soon as the inflight run completes.
	if (this.inflight) {
            this._stepOnce = true;

            // Optional telemetry:
            // this.manager?._emit?.({
            //     type: 'stepDeferredInflight',
            //     name: this.name,
            //     reason: reason || 'step',
            // });

            return;
	}

	// Drain-first semantics while preserving backlog as much as possible:
	// - queue policy: consume ONE queued unit
	// - coalesce: consume pending
	if (this.overlapPolicy === 'queue' && this.queueCount > 0) {
            this.queueCount = Math.max(0, this.queueCount - 1);
            // preserve coalesce intent? queue dominates coalesce for the stepped unit
            // but we do NOT clear pending globally (preserve)
	} else if (this.pending) {
            this.pending = false; // consume exactly one coalesced unit
	}

	// Ensure we run exactly one tick, then pause in finalizeOk/finalizeErr
	this._stepOnce = true;

	// _tick only runs when status === 'running'
	if (this.status !== 'running') {
            this.status = 'running';
	}

	this.lastReason = reason || 'step';

	// Prevent any scheduled normal tick; step should be immediate and singular
	this.backoffMs = 0;
	this._clearTimer();

	this._tick(reason);
    }

    /**
     * Pause this interval.
     * - Stops future ticks but keeps it registered with the manager.
     * - Idempotent.
     *
     * @param {string} [reason='pause']
     * @returns {void}
     */
    pause(reason = 'pause') {
	if (this.status === 'cancelled') return;

	// Update state
	this.status = 'paused';
	this.lastReason = reason || 'pause';

	// Stop any scheduled tick
	this._clearTimer();

	// No longer has a "next run" while paused
	this.nextRunAt = null;
    }
    

    /**
     * Cancel this interval permanently.
     * - Idempotent.
     * - Runs onDestroy (if present) at most once.
     * - Clears timers and prevents future ticks.
     *
     * @param {string} [reason='cancel']
     * @returns {void}
     */
    cancel(reason = 'cancel') {
	if (this.status === 'cancelled') return;

	// Trans first so _runDestructor sees correct status & lastReason
	this.status = 'cancelled';
	this.lastReason = reason || 'cancel';

	this._runDestructor(reason);

	// Now perform cleanup
	this._clearTimer();

	// No future runs
	this.nextRunAt = null;

	// Notify manager for cleanup / telemetry / auto-remove
	if (this.manager && typeof this.manager._maybeAutoRemove === 'function') {
            this.manager._maybeAutoRemove(this);
	}
    }

    /**
     * Reset counters and transient execution state.
     *
     * Semantics:
     * - Does not force a lifecycle transition by itself.
     * - If idle (not inflight), reset applies immediately.
     * - If inflight, reset is deferred until active execution finalizes.
     * - Resets pending/queue/signals/errors/backoff state.
     * - Allows onConstruct to run again on the next eligible tick/start.
     * - If currently running: attempts to schedule an immediate next tick (subject to environment gating).
     * - If currently running and environment policy blocks execution, interval may transition to paused.
     *
     * @returns {void}
     */
    reset() {
	if (this.status === 'cancelled') return;
	if (this.manager?.disposed === true) return;

	const wasRunning = this.status === 'running';

	// Never clear inflight mid-execution. Defer reset until finalize.
	if (this.inflight) {
	    this._resetPending = true;

	    // Prevent immediate re-scheduling/drain while active execution settles.
	    this.pending = false;
	    this.queueCount = 0;
	    this.lastSignal = null;
	    this.backoffMs = null;
	    this._stepOnce = false;
	    this._clearTimer();
	    return;
	}

	this._applyResetState();

	// If we were running, keep running and schedule the next tick again,
	// unless environment gating blocks it (in which case pause explicitly).
	if (wasRunning) {
            const gated =
		  (typeof this._shouldPauseDueToEnvironment === 'function') &&
		  this._shouldPauseDueToEnvironment();

            if (gated) {
		this.pause('environment');
		return;
            }

            // Not gated: schedule ASAP
	    this._scheduleNext(0);
	}
    }

    /**
     * Apply reset state immediately (or from deferred finalize path).
     * Does not change lifecycle status.
     *
     * @private
     * @returns {void}
     */
    _applyResetState() {
	// Counters / timestamps
	this.runs = 0;
	this.lastRunAt = null;
	this.nextRunAt = null;
	this.startedAt = null;

	// Transient execution state
	this.inflight = false;
	this.pending = false;
	this.queueCount = 0;

	this.lastReason = null;
	this.lastError = null;
	this.lastSignal = null;

	// Backoff / error streak bookkeeping
	this.backoffMs = null;
	this._hadErrorSinceSuccess = false;

	// Step mode bookkeeping
	this._stepOnce = false;

	// Allow onConstruct to run again on next tick/start
	this._hasConstructRun = false;
	this._resetPending = false;

	// Clear any pending timer
	this._clearTimer();
    }

    /**
     * If a deferred reset is pending, apply it and reschedule safely.
     *
     * @private
     * @param {Function} scheduleNextIfRunning
     * @returns {boolean} True when reset was consumed and caller should return.
     */
    _consumeDeferredReset(scheduleNextIfRunning) {
	if (!this._resetPending) return false;

	this._applyResetState();

	if (this.status === 'running') {
	    const gated =
		(typeof this._shouldPauseDueToEnvironment === 'function') &&
		this._shouldPauseDueToEnvironment();

	    if (gated) {
		this.pause('environment');
		return true;
	    }

	    this.backoffMs = 0;
	    scheduleNextIfRunning();
	}

	return true;
    }
    /* ===========================
     * Execution
     * =========================== */

    /**
     * Trigger an immediate/ASAP run.
     *
     * Semantics:
     * - If cancelled or manager disposed: no-op.
     * - Obeys environment gating (will not force execution while blocked).
     * - If not running: starts interval and schedules ASAP tick.
     * - If inflight: applies overlapPolicy:
     *   - skip: drop
     *   - coalesce: pending=true
     *   - queue: queueCount++ (bounded by maxQueue unless unbounded)
     *
     * @param {*} payload Currently unused (reserved for future queue payload support).
     * @param {string} [reason='manual']
     * @returns {void}
     */
    
    runNow(payload, reason = 'manual') {
	if (this.status === 'cancelled') return;
	if (this.manager?.disposed === true) return;

	this.lastReason = reason || 'manual';

	// Obey environment gating (do not force execution if policy blocks it)
	if (
            typeof this._shouldPauseDueToEnvironment === 'function' &&
		this._shouldPauseDueToEnvironment()
	) {
            // Optional telemetry:
            // this.manager?._emit?.({
            //     type: 'runBlockedByEnvironment',
            //     name: this.name,
            //     reason: this.lastReason,
            // });
            return;
	}

	// If paused/not-running: manual run implies intent to start + run ASAP
	if (this.status !== 'running') {
            this.backoffMs = 0; // ensure start schedules immediately
            this.start(reason);
            return;
	}

	// If already executing, honor overlap policy
	if (this.inflight) {
            switch (this.overlapPolicy) {
            case 'skip':
		return;

            case 'coalesce':
		this.pending = true;
		return;

            case 'queue': {
		const capped = Number.isFinite(this.maxQueue) && this.maxQueue > 0;
		if (capped && this.queueCount >= this.maxQueue) {
                    // Optional telemetry:
                    // this.manager?._emit?.({
                    //     type: 'queueOverflow',
                    //     name: this.name,
                    // });
                    return;
		}
		this.queueCount += 1;
		this.pending = false; // queue dominates coalesce
		return;
            }

            default:
		// safest fallback is coalesce
		this.pending = true;
		return;
            }
	}

	// Not inflight: schedule immediate tick
	this.backoffMs = 0;
	this._clearTimer();
	this._scheduleNext(0);
    }
    /**
     * Build the execution context object passed to fn(ctx) and lifecycle hooks.
     *
     * @private
     * @param {string} [reason='timer']
     * @returns {import('./types').IntervalContext}
     */
    
    _buildContext(reason = 'timer') {
	const clock = this.manager?.clock;
	const now = clock?.now ? clock.now() : Date.now();

	return {
            // identity
            name: this.name,

            // timing
            now,
            startedAt: this.startedAt,
            lastRunAt: this.lastRunAt,
            nextRunAt: this.nextRunAt,

            // execution counters
            runs: this.runs,
            maxRuns: this.maxRuns,

            // execution metadata
            reason: reason || this.lastReason || 'timer',
            lastReason: this.lastReason,
            lastError: this.lastError,

            // signal state
            lastSignal: this.lastSignal,

            // injected mutable workspace
            workspace: this.workspace,
	    runWhenHidden: this.runWhenHidden,
	    runWhenOffline: this.runWhenOffline,
            // control helpers
            signal: (type, payload) => this.signal(type, payload),
            start: (r) => this.start(r || 'start'),
            pause: (r) => this.pause(r || 'pause'),
            cancel: (r) => this.cancel(r || 'cancel'),
            runNow: (payload, r) => this.runNow(payload, r || 'manual'),
            reschedule: (inMs) => this.reschedule(inMs),

            // interval hints (read-only config)
            everyMs: this.everyMs,
            overlapPolicy: this.overlapPolicy,
            errorPolicy: this.errorPolicy,
            priority: this.priority
	};
    }

    /**
     * Apply a decision object returned from fn(ctx).
     *
     * Supported decisions:
     * - { action: 'pause' }
     * - { action: 'cancel' }
     * - { action: 'reschedule', inMs: number }
     * - { action: 'continue' } (or unknown => no-op)
     *
     * @private
     * @param {*} decision
     * @returns {void}
     */
    _applyDecision(decision) {
	if (!decision || typeof decision !== 'object') return;

	const action = decision.action;
	if (!action) return;

	switch (action) {
        case 'pause':
            this.pause('decision');
            break;

        case 'cancel':
            this.cancel('decision');
            break;

        case 'reschedule': {
            const inMs = Number(decision.inMs);
            if (!Number.isFinite(inMs)) return;
            this.reschedule(inMs);
            break;
        }

        case 'continue':
        default:
            // No-op
            break;
	}
    }
    /* ===========================
     * Scheduling
     * =========================== */

    /**
     * Schedule the next tick after `inMs`.
     * Central scheduling entry point for start/runNow/reschedule/finalize paths.
     * Obeys manager disposal and environment gating.
     *
     * @private
     * @param {number} inMs
     * @returns {void}
     */
    _scheduleNext(inMs) {
	// Do not schedule if not runnable
	if (this.status !== 'running') return;
	if (this.manager?.disposed === true) return;

	// Environment gating (global)
	if (this.manager?.environment?.suspended === true) return;

	// Visibility gating (policy-driven)
	if (typeof this._shouldPauseDueToEnvironment === 'function' && this._shouldPauseDueToEnvironment()) {
            this.nextRunAt = null;
            return;
	}

	const delay = Math.max(0, Number(inMs) || 0);

	const clock = this.manager?.clock;
	const now = (typeof clock?.now === 'function') ? clock.now() : Date.now();

	// Record next scheduled run time
	this.nextRunAt = now + delay;

	//sort of rare, but if you fuck it up... well.. bad things happen.
	const setTimer =
	      (typeof clock?.setTimeout === 'function')
	      ? clock.setTimeout.bind(clock)
	      : setTimeout;
	// Schedule the tick
	this._timer = setTimer(() => {
            this._timer = null;
            this._tick('timer');
	}, delay);
    }

    /**
     * Clear any pending scheduled timer.
     * Safe to call multiple times.
     *
     * @private
     * @returns {void}
     */
    _clearTimer() {
	if (!this._timer) return;
	// Prefer manager clock abstraction if provided
	const clock = this.manager?.clock;
	if (typeof clock?.clearTimeout === 'function') {
	    clock.clearTimeout.call(clock, this._timer);
	} else {
	    clearTimeout(this._timer);
	}
	this._timer = null;
    }
    /**
     * Apply backoff after an error.
     * Sets this.backoffMs only; does not schedule directly.
     *
     * @private
     * @returns {void}
     */
    _applyBackoff() {
	// Only meaningful if still active
	if (this.status !== 'running') return;
	if (this.manager?.disposed === true) return;	

	// Base backoff: start at everyMs, then double
	const base = Math.max(0, Number(this.everyMs) || 0);
	const current =
              (typeof this.backoffMs === 'number' && this.backoffMs >= 0)
              ? this.backoffMs
              : base;

	// Exponential step
	let next = current > 0 ? current * 2 : 0;

	// Cap to prevent runaway delays (default cap: 60s unless overridden)
	const cap = Number(this.manager?.opts?.backoffCapMs);
	const maxCap = Number.isFinite(cap) ? Math.max(0, cap) : 60_000;
	if (next > maxCap) next = maxCap;

	// One-shot override consumed by _tick() scheduler
	this.backoffMs = next;
    }

    /* ===========================
     * Signaling
     * =========================== */
    /**
     * Send a signal to this interval.
     * Signals are stored for the next tick and may be handled once per tick.
     *
     * @param {string} type
     * @param {*} payload
     * @returns {void}
     */
    signal(type, payload) {
	const t = String(type || '');

	this.lastSignal = {
            type: t,
            payload,
            at: (this.manager?.clock?.now ? this.manager.clock.now() : Date.now())
	};

	// Optional: treat signals as a "reason" marker
	// (keeps context readable without forcing policy)
	if (t) this.lastReason = `signal:${t}`;

	// Telemetry hook (optional)
	if (this.manager && typeof this.manager._emit === 'function') {
            this.manager._emit({
		type: 'signal',
		name: this.name,
		signal: this.lastSignal
            });
	}
    }

    /**
     * Reschedule the next tick with a one-shot delay override.
     * Safe to call during execution.
     *
     * @param {number} inMs
     * @returns {void}
     */
    reschedule(inMs) {
	if (this.status === 'cancelled') return;
	if (this.manager?.disposed === true) return;

	const delay = Number(inMs);
	if (!Number.isFinite(delay) || delay < 0) return;

	// One-shot override consumed by _tick() scheduling
	this.backoffMs = delay;

	// Optionally pull the next tick sooner (no synchronous execution)
	if (this.status === 'running' && !this.inflight) {
            this._clearTimer();
            this._scheduleNext(0);
	}
    }

    /**
     * Handle a received signal and optionally mutate lifecycle state.
     * Must not call _tick() (prevents re-entrancy).
     *
     * @private
     * @param {{type:string, payload:any, at:number}} signal
     * @returns {void}
     */
    _handleSignal(signal) {
	if (!signal || typeof signal !== 'object') return;

	const type = String(signal.type || '');
	if (!type) return;

	switch (type) {
        case 'pause':
            this.pause('signal:pause');
            break;

        case 'cancel':
            this.cancel('signal:cancel');
            break;

        case 'start':
        case 'resume':
            this.start(`signal:${type}`);
            break;

        case 'reset':
            this.reset();
            break;

	case 'runNow': {
	    if (this.status !== 'running') this.start('signal:runNow');
	    this.backoffMs = 0;

	    if (this.status === 'running' && !this.inflight) {
		this._clearTimer();
		this._scheduleNext(0);
	    }
	    break;
	}
        default:
            break;
	}
    }
    /* ===========================
     * Introspection
     * =========================== */

    /**
     * Create a serializable snapshot of current interval state.
     *
     * @returns {Object}
     */
    snapshot() {
	return {
            name: this.name,

            // config
            everyMs: this.everyMs,
            maxRuns: this.maxRuns,
            overlapPolicy: this.overlapPolicy,
            errorPolicy: this.errorPolicy,
            priority: this.priority,

            // state
            status: this.status,
            runs: this.runs,
            startedAt: this.startedAt,
            lastRunAt: this.lastRunAt,
            nextRunAt: this.nextRunAt,

            // execution/meta
            inflight: this.inflight,
            pending: this.pending,
            lastReason: this.lastReason,
            lastError: this.lastError ? String(this.lastError.message || this.lastError) : null,
            lastSignal: this.lastSignal,

            // scheduling override
            backoffMs: (typeof this.backoffMs === 'number' ? this.backoffMs : null)
	};
    }

    /**
     * Determine if environment policy should block execution/scheduling right now.
     *
     * @private
     * @returns {boolean}
     */
    _shouldPauseDueToEnvironment() {
	const env = this.manager?.environment ?? {};
	const opts = this.manager?.opts ?? {};

	// Suspended always wins
	if (env.suspended === true) return true;

	// Visibility
	const pauseWhenHidden = opts.pauseWhenHidden !== false;
	if (pauseWhenHidden && env.visible === false && !this.runWhenHidden) {
            return true;
	}

	// Online
	const pauseWhenOffline = opts.pauseWhenOffline !== false; // new opt
	if (pauseWhenOffline && env.online === false && !this.runWhenOffline) {
            return true;
	}

	return false;
    }


    /**
     * Determine if this interval is eligible to execute now.
     *
     * Notes:
     * - If inflight, this may still return true for coalesce/queue policies
     *   (meaning it can accept more work), even though it cannot execute immediately.
     *
     * @returns {boolean}
     */
    isRunnable() {
	// Terminal / global stop conditions
	if (this.status !== 'running') return false;
	// Environment gating (manager-owned signals)
	if (this.manager?.environment?.suspended === true) return false;
	// visibility gate
	if (this._shouldPauseDueToEnvironment()) return false;




	// Max runs reached
	if (this.maxRuns > 0 && this.runs >= this.maxRuns) return false;

	// Overlap rules
	if (this.inflight) {
            // If inflight, only runnable if policy allows pending work
            return this.overlapPolicy === 'queue' || this.overlapPolicy === 'coalesce';
	}

	return true;
    }

    /**
     * Execute one tick of the interval.
     * Handles overlap policy, signals, constructor hook, sync/async fn(ctx), and scheduling.
     *
     * @private
     * @param {string} [reason='timer']
     * @returns {void}
     */
    _tick(reason = 'timer') {
	// Guard: only run when active
	if (this.status !== 'running') return;
	if (this.manager?.disposed === true) return;

	// Optional global gating (manager-owned policy)
	if (this.manager?.environment?.suspended === true) return;

	// Visibility gating
	if (this._shouldPauseDueToEnvironment()) return;
	

	if (this.inflight) {
	    switch (this.overlapPolicy) {
	    case 'skip':
		return;

	    case 'coalesce':
		this.pending = true;
		return;

	    case 'queue': {
		const capped = Number.isFinite(this.maxQueue) && this.maxQueue > 0;
		if (capped && this.queueCount >= this.maxQueue) {
		    // optional telemetry
		    // this.manager?._emit?.({ type: 'queueOverflow', name: this.name });
		    return;
		}
		this.queueCount += 1;
		this.pending = false; // queue dominates coalesce
		return;
	    }
		
	    default:
		this.pending = true;
		return;
	    }
	}
	

	// Max runs pre-check
	if (this.maxRuns > 0 && this.runs >= this.maxRuns) {
            this.cancel('maxRuns');
            if (typeof this.manager?._onIntervalMaxRuns === 'function') {
		this.manager._onIntervalMaxRuns(this);
            }
            return;
	}

	const clock = this.manager?.clock;
	const now = clock?.now ? clock.now() : Date.now();

	// Tick-scoped scheduler helper (one-shot backoff consumption)
	const scheduleNextIfRunning = () => {
            if (this.status !== 'running') return;
	    
            const delay =
		  (typeof this.backoffMs === 'number' && this.backoffMs >= 0)
                  ? this.backoffMs
                  : this.everyMs;

            this.backoffMs = null; // one-shot consume

            this._clearTimer();
            this._scheduleNext(delay);
	};

	const finalizeOk = (decision) => {
	    if (this._consumeDeferredReset(scheduleNextIfRunning)) return;

	    this.runs += 1;
	    this.lastRunAt = now;

	    if (typeof this._applyDecision === 'function') {
		this._applyDecision(decision);
	    }

	    // Clear error backoff after a success
	    if (this._hadErrorSinceSuccess) {
		this.backoffMs = null;
		this._hadErrorSinceSuccess = false;
	    }

	    // Step mode wins: pause after this run, do not schedule/drain
	    if (this._stepOnce) {
		this._stepOnce = false;
		this.pause('step-complete');
		return;
	    }

	    // Max runs post-check
	    if (this.status === 'running' && this.maxRuns > 0 && this.runs >= this.maxRuns) {
		this.cancel('maxRuns');
		if (typeof this.manager?._onIntervalMaxRuns === 'function') {
		    this.manager._onIntervalMaxRuns(this);
		}
		return;
	    }

	    // Queue dominates coalesce: drain one queued run ASAP
	    if (this.status === 'running' && this.overlapPolicy === 'queue' && this.queueCount > 0) {
		this.queueCount -= 1;

		// If any legacy/coalesce state exists, don't let it interfere with queue semantics
		this.pending = false;

		this.backoffMs = 0; // ASAP next tick
		scheduleNextIfRunning();
		return;
	    }

	    // Coalesce behavior: run once more ASAP
	    if (this.status === 'running' && this.pending) {
		this.pending = false;
		this.backoffMs = 0;
		scheduleNextIfRunning();
		return;
	    }

	    scheduleNextIfRunning();
	};	

	const finalizeErr = (err, meta = {}) => {
	    if (this._consumeDeferredReset(scheduleNextIfRunning)) return;

	    this.lastError = err || null;
	    this._hadErrorSinceSuccess = true;

	    // Notify manager / telemetry (never let telemetry throw)
	    try {
		if (typeof this.manager?._onIntervalError === 'function') {
		    this.manager._onIntervalError(this, err);
		} else if (typeof this.manager?._emit === 'function') {
		    const msg =
			  err instanceof Error ? (err.message || String(err)) : String(err);

		    this.manager._emit({
			type: 'error',
			name: this.name,
			error: msg,
		    });
		}
	    } catch (_) {
		// swallow
	    }

	    // Clear coalesce state on error
	    this.pending = false;

	    // Apply queue error policy (only when queue is active)
	    if (this.overlapPolicy === 'queue' && this.queueCount > 0) {
		switch (this.queueErrorPolicy) {
		case QUEUE_ERROR_POLICIES.PRESERVE:
		    break;

		case QUEUE_ERROR_POLICIES.CAP:
		    this.queueCount = Math.min(this.queueCount, 1);
		    break;

		case QUEUE_ERROR_POLICIES.DROP_ONE:
		    this.queueCount = Math.max(0, this.queueCount - 1);
		    break;

		case QUEUE_ERROR_POLICIES.CLEAR:
		default:
		    this.queueCount = 0;
		    break;
		}
	    }

	    // Step mode: pause after this single execution, regardless of errorPolicy
	    if (this._stepOnce) {
		this._stepOnce = false;
		this.pause('step-error');
		return;
	    }

	    // Skip regular errorPolicy for constructor failures
	    const phase = meta && meta.phase;
	    if (phase !== 'construct') {
		switch (this.errorPolicy) {
		case 'pause':
		    this.pause('error');
		    return;

		case 'cancel':
		    this.cancel('error');
		    return;

		case 'backoff':
		    // _applyBackoff is expected to set this.backoffMs (no scheduling)
		    if (typeof this._applyBackoff === 'function') {
			this._applyBackoff();
		    } else {
			this.backoffMs = this.everyMs;
		    }
		    break;

		case 'continue':
		default:
		    break;
		}
	    }

	    scheduleNextIfRunning();
	};
	
	// Mark tick in progress (broad meaning: tick executing)
	this.inflight = true;
	this.lastReason = reason || 'timer';

	// Consume and handle signal once per tick
	if (this.lastSignal && typeof this._handleSignal === 'function') {
            const sig = this.lastSignal;
            this.lastSignal = null;

            try {
		this._handleSignal(sig);
            } catch (err) {
		this.inflight = false;
		finalizeErr(err);
		return;
            }

            // If signal changed lifecycle, stop this tick (no fn execution)
            if (this.status !== 'running') {
		this.inflight = false;
		return;
            }
	}

	// Build context (prefer helper)
	const ctx = (typeof this._buildContext === 'function')
              ? this._buildContext(reason)
              : {
		  name: this.name,
		  now,
		  workspace: this.workspace,
		  runs: this.runs,
		  maxRuns: this.maxRuns,
		  lastRunAt: this.lastRunAt,
		  nextRunAt: this.nextRunAt,
		  reason,
		  signal: (t, p) => this.signal(t, p),
		  pause: (r) => this.pause(r || 'pause'),
		  cancel: (r) => this.cancel(r || 'cancel'),
		  reschedule: (ms) => this.reschedule(ms)
              };



	if (this._tickConstruct(ctx, finalizeOk, finalizeErr)) {
	    // constructor is async and will call _tickContinue later
	    return;
	}

	// constructor either didn't exist, already ran, or completed sync
	this._tickContinue(ctx, finalizeOk, finalizeErr);
    }
    /**
     * Handle a constructor failure according to constructErrorPolicy.
     *
     * @private
     * @param {Error} err
     * @param {Function} finalizeErr
     * @returns {void}
     */
    _handleConstructError(err, finalizeErr) {
	this.inflight = false;
	finalizeErr(err, { phase: 'construct' });

	switch (this.constructErrorPolicy) {
	case 'cancel': this.cancel('construct-error'); break;
	case 'pause': this.pause('construct-error'); break;
	case 'retry':
	default: break;
	}
    }

    /**
     * Run onConstruct with a provided or freshly built context.
     *
     * @private
     * @param {Object} [ctx]
     * @returns {*|Promise<*>} Whatever onConstruct returns
     */
    _runConstructor(ctx) {
	if (!this.onConstruct) return undefined;
	const useCtx = ctx || this._buildContext('construct');
	return this.onConstruct(useCtx); // may throw, may return promise
    }

    /**
     * Ensure onConstruct runs exactly once per lifecycle (or after reset()) before main fn execution.
     * If async, defers continuation until completion.
     *
     * @private
     * @param {Object} ctx
     * @param {Function} finalizeOk
     * @param {Function} finalizeErr
     * @returns {boolean} True if handled (async or error), false if caller should continue synchronously
     */
    _tickConstruct(ctx, finalizeOk, finalizeErr) {
	if (this._hasConstructRun || !this.onConstruct) return false;

	let init;
	try {
	    init = this._runConstructor(ctx);
	} catch (err) {
	    this._handleConstructError(err, finalizeErr);
	    return true;
	}

	if (init && typeof init.then === 'function') {
	    try {
		init.then(() => {
		    this._hasConstructRun = true;
		    this._tickContinue(ctx, finalizeOk, finalizeErr);
		}).catch((err) => {
		    this._handleConstructError(err, finalizeErr);
		});
	    } catch (err) {
		this._handleConstructError(err, finalizeErr);
	    }
	    return true;
	}

	this._hasConstructRun = true;
	return false;
    }

    /**
     * Continue into main fn(ctx) execution after constructor hook (if any).
     *
     * Note:
     * - This method re-checks lifecycle state before invoking `fn`, because async
     *   onConstruct completion may arrive after pause/cancel/dispose transitions.
     *
     * @private
     * @param {Object} ctx
     * @param {Function} finalizeOk
     * @param {Function} finalizeErr
     * @returns {void}
     */
    _tickContinue(ctx, finalizeOk, finalizeErr) {
	// onConstruct may resolve after lifecycle changes (cancel/pause/dispose).
	// Re-check run eligibility before invoking user callback.
	if (this.status !== 'running' || this.manager?.disposed === true) {
	    this.inflight = false;
	    return;
	}

	// Execute callback (sync or async)
	let out;
	try {
	    out = this.fn ? this.fn(ctx) : undefined;
	} catch (err) {
	    this.inflight = false;
	    finalizeErr(err);
	    return;
	}

	if (out && typeof out.then === 'function') {
	    out.then((decision) => {
		this.inflight = false;
		finalizeOk(decision);
	    }).catch((err) => {
		this.inflight = false;
		finalizeErr(err);
	    });
	    return;
	}

	this.inflight = false;
	finalizeOk(out);
    }

    /**
     * Track + optionally emit warnings for onDestroy failures.
     *
     * @private
     * @param {string} reason
     * @param {*} err
     * @param {boolean} [thenable=false]
     * @returns {void}
     */
    _warnOnDestroyError(reason, err, thenable = false) {
	this.lastError = err;
	if (this.warnOnDestroyError !== true) return;
	if (typeof console === 'undefined' || typeof console.warn !== 'function') return;

	if (thenable) {
	    console.warn(`onDestroy thenable failed for "${this.name}" (reason: ${reason})`, err);
	    return;
	}

	console.warn(`onDestroy failed for "${this.name}" (reason: ${reason})`, err);
    }

    /**
     * Run the onDestroy hook (if present). Never prevents cancellation.
     *
     * @private
     * @param {string} reason
     * @returns {void}
     */
    _runDestructor(reason) {
	if (!this.onDestroy) return;

	try {
	    const ctx = this._buildContext('destroy');
	    const out = this.onDestroy(ctx, reason);

	    if (out && typeof out.then === 'function') {
		try {
		    out.catch(err => {
			this._warnOnDestroyError(reason, err, false);
		    });
		} catch (err) {
		    this._warnOnDestroyError(reason, err, true);
		}
	    }
	} catch (err) {
	    this._warnOnDestroyError(reason, err, false);
	}
    }    
}

export {ManagedInterval};
export default ManagedInterval;
