/**
 * IntervalManager
 * ----------------
 * Central registry and lifecycle controller for named intervals.
 *
 * Responsibilities:
 * - Maintains a registry of named ManagedInterval instances
 * - Provides lifecycle control (start/pause/resume/cancel/stopAll/dispose)
 * - Provides manual triggering (runNow/step) and signaling
 * - Tracks and applies environment state (visibility / online / suspension)
 * - Emits optional telemetry via opts.onEvent
 */
import { ManagedInterval } from './ManagedInterval.js';

/**
 * Create a new IntervalManager.
 *
 * @param {Object} [opts]
 * @param {boolean} [opts.autoRemove=true]
 *        Automatically remove cancelled intervals from the registry (via _maybeAutoRemove).
 *
 * @param {boolean} [opts.pauseWhenHidden=true]
 *        If true, intervals are paused when environment.visible becomes false,
 *        unless the interval allows running while hidden (interval.runWhenHidden).
 *
 * @param {boolean} [opts.pauseWhenOffline=true]
 *        If true, intervals are paused when environment.online becomes false,
 *        unless the interval allows running while offline (interval.runWhenOffline).
 *
 * @param {number} [opts.backoffCapMs=60000]
 *        Maximum delay cap for ManagedInterval backoff policy. Values < 0 are clamped to 0.
 *
 * @param {boolean} [opts.warnOnDestroyError=true]
 *        If true, ManagedInterval may emit console warnings when onDestroy hooks fail.
 *
 * @param {Function|null} [opts.onEvent]
 *        Optional lifecycle / telemetry hook.
 *        Called with a structured event object.
 *
 *        Common event types include:
 *        - register
 *        - start / pause / resume / cancel
 *        - runNow / step
 *        - environment
 *        - error
 *        - maxRuns
 *        - remove
 *        - dispose
 *
 * @param {Object|null} [opts.clock]
 *        Optional clock abstraction for time control and testing.
 *        If omitted, native Date.now / setTimeout will be used.
 *        Expected shape:
 *        {
 *          now(): number,
 *          setTimeout(fn, ms): any,
 *          clearTimeout(id): void
 *        }
 *
 * @param {Object} [opts.environment]
 *        Optional initial environment state.
 *        Keys: visible:boolean, online:boolean, suspended:boolean
 *
 * @example1
 * const manager = new IntervalManager({
 *   autoRemove: true,
 *   pauseWhenHidden: true,
 *   pauseWhenOffline: true,
 *   onEvent: (e) => console.log(e),
 *   environment: { visible: true, online: true, suspended: false }
 * });
 * @example2
 * // Sample JSON-style configuration
 * {
 *   "autoRemove": true,
 *   "pauseWhenHidden": true,
 *   "pauseWhenOffline": false,
 *   "onEvent": "(info) => console.log(info)",
 *   "clock": {
 *     "now": "() => Date.now()",
 *     "setTimeout": "setTimeout",
 *     "clearTimeout": "clearTimeout"
 *   },
 *   "environment": {
 *     "visible": true,
 *     "online": true,
 *     "suspended": false
 *   }
 * }
 */



class IntervalManager {
    /**
     * Normalized options with documented defaults.
     * @type {{
     *   autoRemove: boolean,
     *   pauseWhenHidden: boolean,
     *   pauseWhenOffline: boolean,
     *   backoffCapMs: (number|undefined),
     *   warnOnDestroyError: boolean,
     *   onEvent: Function|null,
     *   environment: Object
     * }}
     */
    constructor(opts = {}) {
	// Normalize options with documented defaults
	this.opts = {
	    autoRemove: opts.autoRemove !== false, // default true
	    pauseWhenHidden: opts.pauseWhenHidden !== false, // default true
	    pauseWhenOffline: opts.pauseWhenOffline !== false, // default true
	    backoffCapMs: Number.isFinite(Number(opts.backoffCapMs))
		? Math.max(0, Number(opts.backoffCapMs))
		: undefined,
	    warnOnDestroyError: opts.warnOnDestroyError !== false, // default true
	    onEvent: typeof opts.onEvent === 'function' ? opts.onEvent : null,
	    environment: opts.environment && typeof opts.environment === 'object'
		? opts.environment
		: {},
	};

	/**
         * Optional clock abstraction (used by ManagedInterval).
         * @type {Object|null}
         */
	this.clock = opts.clock || null;

	/**
         * Registry of ManagedInterval instances by name.
         * @type {Map<string, ManagedInterval>}
         */
	this.intervals = new Map();

	/**
         * Current environment state used for policy (visibility / online / suspension).
         * @type {{visible: boolean, online: boolean, suspended: boolean}}
         */
	this.environment = {
	    visible: true,
	    online: true,
	    suspended: false,
	    ...(this.opts.environment || {}),
	};

	/**
         * Disposal guard. Once disposed, most public APIs throw.
         * @type {boolean}
         */
	this.disposed = false;
	
    }
    
    /* ===========================
     * Registration / Lookup
     * =========================== */

    /**
     * Register a new interval (or replace existing by name).
     *
     * Replacement behavior:
     * - If an interval with the same name exists, it is cancelled with reason "replaced"
     *   before being overwritten.
     *
     * @param {Object} config
     * @param {string} config.name - Unique interval name (registry key).
     * @param {Function} config.fn - Tick function (sync or async).
     * @returns {ManagedInterval}
     * @throws {Error|TypeError} on invalid input or if manager is disposed.
     */
    register(config) {
	if (this.disposed) {
	    throw new Error('IntervalManager has been disposed');
	}

	if (!config || typeof config !== 'object') {
	    throw new TypeError('IntervalManager.register(config): config must be an object');
	}

	const name = String(config.name ?? '').trim();
	if (!name) {
	    throw new TypeError('IntervalManager.register(config): config.name is required');
	}

	if (typeof config.fn !== 'function') {
	    throw new TypeError(`IntervalManager.register("${name}"): config.fn must be a function`);
	}

	// Replace existing interval safely
	const existing = this.intervals.get(name);
	if (existing) {
	    // Cancel to ensure no timers survive replacement
	    existing.cancel('replaced');
	}

	// Ensure the name is normalized to our registry key
	const interval = new ManagedInterval(this, { ...config, name });

	this.intervals.set(name, interval);

	// Emit telemetry (avoid including the function itself)
	this._emit({
	    type: 'register',
	    name,
	    config: {
		everyMs: interval.everyMs,
		maxRuns: interval.maxRuns,
		priority: interval.priority,
		overlapPolicy: interval.overlapPolicy,
		errorPolicy: interval.errorPolicy,
		runWhenHidden: interval.runWhenHidden,
		runWhenOffline: interval.runWhenOffline
	    }
	});

	return interval;
    }

    /**
     * Return a serializable snapshot of one interval (by name) or all intervals.
     *
     * @param {string} [name]
     * @returns {Object|null} Interval snapshot object, map of snapshots, or null if not found.
     */
    snapshot(name) {
	if (name) {
	    const interval = this._get(name);
	    return interval ? interval.snapshot() : null;
	}

	const out = {};
	for (const [key, interval] of this.intervals.entries()) {
	    out[key] = interval.snapshot();
	}
	return out;
    }

    /* ===========================
     * Lifecycle Control
     * =========================== */

    /**
     * Start an interval by name, or start all intervals.
     *
     * Notes:
     * - Start requests are immediately followed by _applyEnvironmentPolicy()
     *   to ensure "start/resume ignoring environment state" cannot occur.
     *
     * @param {string} [name]
     * @returns {ManagedInterval|ManagedInterval[]|null}
     */
    start(name) {
	this._assertNotDisposed();

	// Start one
	if (typeof name === 'string' && name.trim()) {
	    const interval = this._get(name);
	    if (!interval) return null;

	    interval.start('start');
	    this._emit({ type: 'start', name: interval.name });

	    // Enforce environment gating immediately
	    this._applyEnvironmentPolicy();

	    return interval;
	}

	// Start all
	for (const interval of this.intervals.values()) {
	    interval.start('start');
	    this._emit({ type: 'start', name: interval.name });
	}

	// Enforce environment gating immediately
	this._applyEnvironmentPolicy();

	return Array.from(this.intervals.values());
    }
    
    /**
     * Pause an interval by name, or pause all intervals.
     *
     * @param {string} [name]
     * @returns {ManagedInterval|ManagedInterval[]|null}
     */
    pause(name) {
	this._assertNotDisposed();

	if (typeof name === 'string' && name.trim()) {
	    const interval = this._get(name);
	    if (!interval) return null;

	    interval.pause('pause');
	    this._emit({ type: 'pause', name: interval.name });
	    return interval;
	}

	for (const interval of this.intervals.values()) {
	    interval.pause('pause');
	    this._emit({ type: 'pause', name: interval.name });
	}

	return Array.from(this.intervals.values());
    }

    
    /**
     * Resume an interval by name, or resume all intervals.
     *
     * Notes:
     * - Resumes are immediately followed by _applyEnvironmentPolicy()
     *   so intervals that should remain paused due to environment do not thrash.
     *
     * @param {string} [name]
     * @returns {ManagedInterval|ManagedInterval[]|null}
     */
    resume(name) {
	this._assertNotDisposed();

	if (typeof name === 'string' && name.trim()) {
	    const interval = this._get(name);
	    if (!interval) return null;

	    interval.start('resume');
	    this._emit({ type: 'resume', name: interval.name });

	    // Enforce environment gating immediately
	    this._applyEnvironmentPolicy();

	    return interval;
	}

	for (const interval of this.intervals.values()) {
	    interval.start('resume');
	    this._emit({ type: 'resume', name: interval.name });
	}

	// Enforce environment gating immediately
	this._applyEnvironmentPolicy();

	return Array.from(this.intervals.values());
    }

    /**
     * Cancel an interval by name, or cancel all intervals.
     *
     * @param {string} [name]
     * @returns {ManagedInterval|ManagedInterval[]|null}
     */
    
    cancel(name) {
	this._assertNotDisposed();

	if (typeof name === 'string' && name.trim()) {
	    const interval = this._get(name);
	    if (!interval) return null;

	    interval.cancel('cancel');
	    this._emit({ type: 'cancel', name: interval.name });
	    return interval;
	}

	for (const interval of this.intervals.values()) {
	    interval.cancel('cancel');
	    this._emit({ type: 'cancel', name: interval.name });
	}

	return Array.from(this.intervals.values());
    }
    
    /**
     * Dispose the manager and permanently stop all intervals.
     *
     * Notes:
     * - Cancels all intervals (reason: "dispose")
     * - Clears registry
     * - After disposal, most public APIs throw.
     */

    dispose() {
	if (this.disposed) return;

	this.disposed = true;

	// Cancel all intervals safely
	for (const interval of Array.from(this.intervals.values())) {
	    interval.cancel('dispose');
	}

	// Clear registry explicitly (in case autoRemove is disabled)
	this.intervals.clear();

	this._emit({ type: 'dispose' });
    }
    

    /* ===========================
     * Execution / Signaling
     * =========================== */

    /**
     * Trigger an immediate run of a named interval.
     *
     * Delegates to ManagedInterval.runNow(payload, 'runNow').
     * Overlap, queuing, and environment gating are handled inside the interval.
     *
     * @param {string} name
     * @param {*} [payload]
     * @returns {ManagedInterval|null}
     */
    runNow(name, payload) {
	this._assertNotDisposed();

	const interval = this._get(name);
	if (!interval) return null;

	interval.runNow(payload, 'runNow');

	this._emit({
	    type: 'runNow',
	    name: interval.name,
	});

	return interval;
    }

    /**
     * Execute exactly one run for an interval (debug / stepping).
     *
     * Delegates to ManagedInterval.step(reason).
     * The precise semantics of "step" are defined by ManagedInterval, but the intent is:
     * - attempt a single execution now
     * - do not enable continuous running as a side effect
     *
     * @param {string} name
     * @param {string} [reason='step']
     * @returns {ManagedInterval|null}
     */
    step(name, reason = 'step') {
	this._assertNotDisposed();

	const interval = this._get(name);
	if (!interval) return null;

	interval.step(reason);

	this._emit({
	    type: 'step',
	    name: interval.name,
	    reason,
	});

	return interval;
    }   

    
    /**
     * Send a signal to a named interval.
     *
     * @param {string} name
     * @param {string} type
     * @param {*} [payload]
     * @returns {ManagedInterval|null}
     */
    signal(name, type, payload) {
	this._assertNotDisposed();

	const interval = this._get(name);
	if (!interval) return null;

	interval.signal(type, payload);
	return interval;
    }

    /**
     * Broadcast a signal to all intervals.
     *
     * @param {string} type
     * @param {*} [payload]
     * @returns {ManagedInterval[]}
     */
    signalAll(type, payload) {
	this._assertNotDisposed();

	for (const interval of this.intervals.values()) {
	    interval.signal(type, payload);
	}

	return Array.from(this.intervals.values());
    }

    /**
     * Stop all intervals immediately.
     *
     * Equivalent to cancelling all intervals with reason "stopAll".
     * Unlike dispose(), the manager remains usable afterward.
     *
     * @returns {ManagedInterval[]}
     */
    stopAll() {
	this._assertNotDisposed();

	const intervals = Array.from(this.intervals.values());

	for (const interval of intervals) {
	    interval.cancel('stopAll');
	    this._emit({ type: 'cancel', name: interval.name, reason: 'stopAll' });
	}

	return intervals;
    }
    /**
     * Replace or inject a workspace object into an interval.
     *
     * @param {string} name
     * @param {object} workspace
     * @returns {ManagedInterval|null}
     * @throws {TypeError} if workspace is not an object.
     */
    setWorkspace(name, workspace) {
	this._assertNotDisposed();

	const interval = this._get(name);
	if (!interval) return null;

	if (workspace == null || typeof workspace !== 'object') {
	    throw new TypeError(`IntervalManager.setWorkspace("${name}"): workspace must be an object`);
	}

	interval.workspace = workspace;

	this._emit({
	    type: 'workspace',
	    name: interval.name,
	});

	return interval;
    }
    /* ===========================
     * Environment / System Hooks
     * =========================== */

    /**
     * Update environment state (visibility, online, suspended).
     *
     * Only recognized keys are applied: visible, online, suspended.
     * If any recognized value changes, emits an "environment" event and re-applies policy.
     *
     * @param {{visible?: boolean, online?: boolean, suspended?: boolean}} info
     */
    updateEnvironment(info = {}) {
	this._assertNotDisposed();

	if (!info || typeof info !== 'object') return;

	const prev = { ...this.environment };

	// Only accept known keys
	if (typeof info.visible === 'boolean') this.environment.visible = info.visible;
	if (typeof info.online === 'boolean') this.environment.online = info.online;
	if (typeof info.suspended === 'boolean') this.environment.suspended = info.suspended;

	// Emit only if something actually changed
	if (
	    prev.visible !== this.environment.visible ||
		prev.online !== this.environment.online ||
		prev.suspended !== this.environment.suspended
	) {
	    this._emit({
		type: 'environment',
		prev,
		next: { ...this.environment },
	    });

	    this._applyEnvironmentPolicy();
	}
    }
    
    /**
     * Apply current environment policy to all intervals.
     *
     * Policy order:
     * 1) suspended: pauses all running intervals (hard stop)
     * 2) hidden: pauses/resumes intervals that do not allow runWhenHidden
     * 3) offline: pauses/resumes intervals that do not allow runWhenOffline
     *
     * Thrash avoidance:
     * - Resumes only occur when the interval is allowed to run under current env
     *   (e.g. don't resume from "hidden" if still offline and pauseWhenOffline is enabled).
     *
     * @private
     */
    _applyEnvironmentPolicy() {
	const pauseHiddenEnabled = this.opts.pauseWhenHidden !== false;
	const pauseOfflineEnabled = this.opts.pauseWhenOffline !== false;

	const isHidden = this.environment.visible === false;
	const isOffline = this.environment.online === false;

	// Helper: should this interval be allowed to run right now?
	const canRunNow = (interval) => {
	    if (pauseHiddenEnabled && isHidden && !interval.runWhenHidden) return false;
	    if (pauseOfflineEnabled && isOffline && !interval.runWhenOffline) return false;
	    return true;
	};

	// 1) Suspension is a hard global stop.
	if (this.environment.suspended === true) {
	    for (const interval of this.intervals.values()) {
		if (interval.status === 'running') {
		    interval.pause('suspended');
		    this._emit({ type: 'pause', name: interval.name, reason: 'suspended' });
		}
	    }
	    return;
	}

	// Resume only those paused due to suspension, but only if allowed by current env.
	for (const interval of this.intervals.values()) {
	    if (interval.status === 'paused' && interval.lastReason === 'suspended') {
		if (!canRunNow(interval)) continue;

		interval.start('unsuspended');
		this._emit({ type: 'resume', name: interval.name, reason: 'unsuspended' });
	    }
	}

	// 2) Visibility policy (if enabled)
	if (pauseHiddenEnabled) {
	    if (isHidden) {
		for (const interval of this.intervals.values()) {
		    if (interval.status !== 'running') continue;

		    if (!interval.runWhenHidden) {
			interval.pause('hidden');
			this._emit({ type: 'pause', name: interval.name, reason: 'hidden' });
		    }
		}
	    } else {
		// Visible again: resume only if not blocked by offline policy
		for (const interval of this.intervals.values()) {
		    if (interval.status === 'paused' && interval.lastReason === 'hidden') {
			if (!canRunNow(interval)) continue;

			interval.start('visible');
			this._emit({ type: 'resume', name: interval.name, reason: 'visible' });
		    }
		}
	    }
	}

	// 3) Online policy (if enabled)
	if (pauseOfflineEnabled) {
	    if (isOffline) {
		for (const interval of this.intervals.values()) {
		    if (interval.status !== 'running') continue;

		    if (!interval.runWhenOffline) {
			interval.pause('offline');
			this._emit({ type: 'pause', name: interval.name, reason: 'offline' });
		    }
		}
	    } else {
		// Online again: resume only if not blocked by hidden policy
		for (const interval of this.intervals.values()) {
		    if (interval.status === 'paused' && interval.lastReason === 'offline') {
			if (!canRunNow(interval)) continue;

			interval.start('online');
			this._emit({ type: 'resume', name: interval.name, reason: 'online' });
		    }
		}
	    }
	}
    }


    

    /* ===========================
     * Internal Hooks
     * =========================== */

    /**
     * Handle interval execution errors (telemetry hook called by ManagedInterval).
     *
     * @param {ManagedInterval} interval
     * @param {Error} error
     * @private
     */
    _onIntervalError(interval, error) {
	// Never let telemetry/error handling crash the scheduler
	try {
	    const name = interval?.name ?? '(unknown)';

	    this._emit({
		type: 'error',
		name,
		message: error?.message,
		stack: error?.stack,
	    });

	    // Policy hook (conservative default):
	    // ManagedInterval already applies its own errorPolicy behavior.
	    // The manager should not double-cancel/pause unless you explicitly want that.
	} catch (_) {
	    // swallow
	}
    }
    /**
     * Handle maxRuns reached (telemetry hook called by ManagedInterval).
     *
     * @param {ManagedInterval} interval
     * @private
     */
    _onIntervalMaxRuns(interval) {
	try {
	    const name = interval?.name ?? '(unknown)';

	    this._emit({
		type: 'maxRuns',
		name,
	    });

	    // Conservative default:
	    // ManagedInterval will usually cancel itself on maxRuns.
	    // If it doesn't, we can safely cancel here as a backstop.
	    if (interval && typeof interval.cancel === 'function') {
		interval.cancel('maxRuns');
	    }
	} catch (_) {
	    // swallow
	}
    }
    
    /**
     * Remove cancelled intervals if configured.
     * Called by ManagedInterval.cancel().
     *
     * @param {ManagedInterval} interval
     * @private
     */
    _maybeAutoRemove(interval) {
	if (!interval) return;

	// Default is auto-remove unless explicitly disabled
	if (this.opts.autoRemove === false) return;

	const name = interval.name;
	if (!name) return;

	// Only remove if it is still the same instance
	const current = this.intervals.get(name);
	if (current !== interval) return;

	this.intervals.delete(name);

	this._emit({
	    type: 'remove',
	    name,
	});
    }
    /**
     * Emit lifecycle / telemetry events.
     *
     * @param {Object} event
     * @private
     */
    _emit(event) {
	const handler = this.opts.onEvent;
	if (!handler) return;

	try {
	    handler(event);
	} catch (err) {
	    // Telemetry must never break interval execution
	    // Swallow errors intentionally
	    // (Optionally console.warn here if you want visibility)
	}
    }

    /**
     * Throw if manager has been disposed.
     * @private
     */
    _assertNotDisposed() {
	if (this.disposed) {
	    throw new Error('IntervalManager has been disposed');
	}
    }

    /**
     * Check if an interval exists by name.
     *
     * @param {string} name
     * @returns {boolean}
     */
    has(name) {
	return !!this._get(name);
    }
    /**
     * Get a ManagedInterval by name. Returns null if not found.
     *
     * @param {string} name
     * @returns {ManagedInterval|null}
     */

    get(name) {
	return this._get(name);
    }


    /**
     * Return a list of all managed interval names.
     *
     * @returns {string[]}
     */
    list() {
	return Array.from(this.intervals.keys());
    }
    /**
     * Internal name normalization + lookup.
     *
     * @param {string} name
     * @returns {ManagedInterval|null}
     * @private
     */
    _get(name) {
	const key = String(name ?? '').trim();
	if (!key) return null;
	return this.intervals.get(key) || null;
    }
    
    
}
export { IntervalManager };
export default IntervalManager;
