import { IntervalManager } from './IntervalManager.js';
import { ManagedInterval } from './ManagedInterval.js';

const MOD = '[primitive.interval]';
const SERVICE_ID = 'primitive.interval';

/**
 * IntervalManager-like shape accepted by installer wiring.
 *
 * @typedef {Object} IntervalManagerLike
 * @property {Function} register
 * @property {Function} start
 * @property {Function} pause
 * @property {Function} resume
 * @property {Function} cancel
 * @property {Function} dispose
 */

/**
 * install(lib, opts?)
 *
 * m7-js-lib integration installer for this primitive.
 *
 * This installer is for m7-js-lib namespace/service wiring only:
 * - Registers constructors at `lib.primitive.interval`
 * - Optionally registers a shared manager instance (if `lib.service.set` exists)
 * - Reuses an existing service only when it is IntervalManager-compatible
 *
 * Standalone usage:
 * If you are using this library standalone, this installer is not required.
 * Import `IntervalManager` directly from `./IntervalManager.js`.
 *
 * @param {Object} lib
 * @param {Object} [opts]
 * @param {IntervalManagerLike|null} [opts.instance]
 * @param {boolean} [opts.force=false]
 * @param {Object} [opts.managerOptions]
 * @param {boolean} [opts.start=false]
 * @returns {{
 *   namespace: Object,
 *   instance: IntervalManagerLike|null,
 *   installedService: boolean
 * }}
 * @throws {Error}
 *  - when `lib` is invalid
 *  - when `lib.hash.set` is missing
 *  - when `opts.instance` is provided but not IntervalManager-compatible
 */
export function install(lib, opts = {}) {
    if (!lib || typeof lib !== 'object') {
        throw new Error(`${MOD} install(lib) requires an m7-lib instance object.`);
    }

    if (!lib.hash || typeof lib.hash.set !== 'function') {
        throw new Error(`${MOD} install(lib) requires lib.hash.set.`);
    }

    const hasHashGet = !!(lib.hash && typeof lib.hash.get === 'function');
    const hasServiceSet = !!(lib.service && typeof lib.service.set === 'function');
    const hasServiceGet = !!(lib.service && typeof lib.service.get === 'function');

    let namespace = null;
    if (hasHashGet) {
        try {
            namespace = lib.hash.get(lib, SERVICE_ID);
        } catch (err) {
            namespace = null;
        }
    }
    if (!namespace || typeof namespace !== 'object') {
        namespace = {};
    }

    // Keep legacy keys while also exposing explicit constructor names.
    namespace.Manager = IntervalManager;
    namespace.Interval = ManagedInterval;
    namespace.IntervalManager = IntervalManager;
    namespace.ManagedInterval = ManagedInterval;
    lib.hash.set(lib, SERVICE_ID, namespace);

    let instance = null;
    let installedService = false;
    const shouldStart = !!(opts && opts.start === true);
    const providedInstanceRaw =
        opts && Object.prototype.hasOwnProperty.call(opts, 'instance')
            ? opts.instance
            : null;
    const providedInstance =
        providedInstanceRaw == null
            ? null
            : assertManagerInstance(providedInstanceRaw, 'opts.instance');

    if (hasServiceSet) {
        const force = opts && opts.force === true;
        const existingInstanceRaw = hasServiceGet ? lib.service.get(SERVICE_ID) : null;
        const existingInstance = isIntervalManagerLike(existingInstanceRaw)
            ? existingInstanceRaw
            : null;

        if (!force && existingInstance) {
            instance = existingInstance;
        } else if (providedInstance) {
            instance = providedInstance;
        } else {
            const managerOptions =
                opts && opts.managerOptions && typeof opts.managerOptions === 'object'
                    ? opts.managerOptions
                    : {};

            instance = new IntervalManager(managerOptions);
        }

        lib.service.set(SERVICE_ID, instance);
        namespace.instance = instance;
        installedService = true;

        // Re-write namespace to ensure `instance` is present after install.
        lib.hash.set(lib, SERVICE_ID, namespace);
    } else if (providedInstance) {
        namespace.instance = providedInstance;
        lib.hash.set(lib, SERVICE_ID, namespace);
        instance = providedInstance;
    }

    if (shouldStart && instance && typeof instance.start === 'function') {
        instance.start();
    }

    return {
        namespace,
        instance,
        installedService,
    };
}

export { IntervalManager, ManagedInterval, SERVICE_ID };
export default install;

/**
 * Validate a provided manager instance candidate.
 *
 * @private
 * @param {*} candidate
 * @param {string} label
 * @returns {IntervalManagerLike}
 * @throws {Error}
 */
function assertManagerInstance(candidate, label) {
    if (!isIntervalManagerLike(candidate)) {
        throw new Error(`${MOD} install(lib) ${label} must be an IntervalManager-compatible instance.`);
    }
    return candidate;
}

/**
 * Detect whether a value satisfies the minimal manager contract.
 *
 * @private
 * @param {*} value
 * @returns {boolean}
 */
function isIntervalManagerLike(value) {
    if (!value || typeof value !== 'object') return false;
    if (value instanceof IntervalManager) return true;

    return REQUIRED_MANAGER_METHODS.every((name) => typeof value[name] === 'function');
}

const REQUIRED_MANAGER_METHODS = Object.freeze([
    'register',
    'start',
    'pause',
    'resume',
    'cancel',
    'dispose',
]);
